insert into competitions (code, name) values ('KWSCIL','Kent Women’s Softball Cricket Indoor League'),('TIL','Tonbridge Indoor League'),('KWSCL','Kent Women’s Softball Cricket League Festivals'),('KWSB','Kent Women’s Softball Bash'),('Friendlies','Friendlies'),('Tournaments','Tournaments') on conflict (code) do update set name = excluded.name;
insert into competition_divisions (competition_id, code, name, sort_order) select c.id, v.code, v.name, v.sort_order from competitions c join (values ('KWSB','KWSB-WEST','West',1),('KWSB','KWSB-CENTRAL','Central',2)) as v(comp_code, code, name, sort_order) on v.comp_code = c.code on conflict (code) do update set name = excluded.name, sort_order = excluded.sort_order;
